class PortfolioCard extends React.Component {
    constructor(props) {
        super(props)
    }
  render() {
    const settings = {
        dots: true,
        infinite: true,
        speed: 500,
        slidesToShow: 1,
        slidesToScroll: 1
      };
    return (
        <>
            <Container style={{width:"100%", marginTop:"50px"}}>
                <Card style={{background: '#D9DDE2', marginBottom: "20px"}}>

                <Container width="60%">
                    <div>
                        <Slider {...settings}>
                        <div style={{alignText:"center"}}>
                            <img width="50%" src={this.props.image1}></img>
                        </div>
                        <div>
                            <img width="50%" src={this.props.image2}></img>
                        </div>
                        </Slider>
                    </div>
                </Container>
                <Row>
                    <Col>
                    <Card.Body>
                    <Card.Title className="text-muted"><h1>{this.props.film}</h1></Card.Title>
                    <p>{this.props.description}</p>
                    </Card.Body>
                    </Col>
                    </Row>
                    <Card.Footer>
                    <div style={{textAlign: "center"}}>
                        <small>{this.props.date}</small>
                    </div>
                    </Card.Footer>

                </Card>

            </Container>
        </>
    )
  }
}

export default PortfolioCard
